// ============================================================================
// CSV Parser Library
// ============================================================================

/**
 * Configuration options for the CSV parser.
 */
export interface CSVOptions {
  /** Field delimiter character (default: ",") */
  delimiter?: string;
  /** Quote character for wrapping fields (default: '"') */
  quote?: string;
  /** Line separator (default: auto-detect \r\n, \r, or \n) */
  lineSeparator?: string;
  /** Whether to automatically coerce types (default: true) */
  typeCoercion?: boolean;
}

/**
 * Represents a parsing error on a specific row.
 */
export interface CSVError {
  /** 1-based row number where the error occurred (excluding header row) */
  row: number;
  /** Human-readable description of the error */
  message: string;
}

/**
 * The result of parsing a CSV string, including data, metadata, and
 * chainable utility methods for filtering and aggregation.
 */
export interface CSVResult {
  /** Parsed data rows as an array of objects keyed by header names */
  rows: Record<string, unknown>[];
  /** Column names extracted from the first row */
  headers: string[];
  /** Collection of non-fatal parsing errors encountered */
  errors: CSVError[];

  /**
   * Returns a new CSVResult containing only rows that satisfy the predicate.
   */
  filter(predicate: (row: Record<string, unknown>) => boolean): CSVResult;

  /**
   * Sums all numeric values in the given column. Non-numeric values are ignored.
   */
  sum(column: string): number;

  /**
   * Averages all numeric values in the given column. Non-numeric values are ignored.
   * Returns NaN if no numeric values exist.
   */
  average(column: string): number;

  /**
   * Returns the total number of data rows.
   */
  count(): number;

  /**
   * Groups rows by the values in the given column.
   * Returns a Map where keys are the distinct column values (as strings)
   * and values are arrays of matching row objects.
   */
  groupBy(column: string): Map<string, Record<string, unknown>[]>;
}

// ============================================================================
// Internal helpers
// ============================================================================

const DEFAULT_OPTIONS: Required<CSVOptions> = {
  delimiter: ",",
  quote: '"',
  lineSeparator: "",      // empty string = auto-detect
  typeCoercion: true,
};

/**
 * Coerce a raw string value into a typed JavaScript value.
 *
 * Conversion rules (applied in order):
 *  1. null / NULL / empty string  → null
 *  2. true / false (case-insensitive) → boolean
 *  3. numeric string (integer or float, including negative) → number
 *  4. everything else → string (unchanged)
 */
function coerceValue(raw: string): unknown {
  // Null-like values
  if (raw === "" || raw.toLowerCase() === "null") {
    return null;
  }

  // Boolean values
  const lower = raw.toLowerCase();
  if (lower === "true") return true;
  if (lower === "false") return false;

  // Numeric values – must match the *entire* string
  // We intentionally reject strings like "" (already handled), "  ", "Infinity", "NaN"
  if (/^-?(\d+\.?\d*|\.\d+)$/.test(raw)) {
    const num = Number(raw);
    if (Number.isFinite(num)) return num;
  }

  return raw;
}

/**
 * Split the input into lines respecting the configured (or auto-detected)
 * line separator.  When auto-detecting we support \r\n, \r, and \n.
 */
function splitLines(input: string, lineSeparator: string): string[] {
  if (lineSeparator) {
    return input.split(lineSeparator);
  }
  // Auto-detect: normalise all line endings to \n, then split
  return input.replace(/\r\n/g, "\n").replace(/\r/g, "\n").split("\n");
}

/**
 * Parse a single CSV line into an array of raw string field values,
 * handling quoted fields and escaped quotes.
 *
 * Returns `{ fields, error }`.  If a quoting / structural error is detected
 * we still return whatever fields we managed to extract and set `error` to a
 * description string.
 */
function parseLine(
  line: string,
  delimiter: string,
  quote: string
): { fields: string[]; error: string | null } {
  const fields: string[] = [];
  let current = "";
  let inQuotes = false;
  let i = 0;
  let error: string | null = null;

  while (i < line.length) {
    const ch = line[i];

    if (inQuotes) {
      if (ch === quote) {
        // Look ahead – escaped quote?
        if (i + 1 < line.length && line[i + 1] === quote) {
          current += quote;
          i += 2;
          continue;
        }
        // End of quoted field
        inQuotes = false;
        i++;
        // After closing quote we expect either delimiter or end-of-line
        if (i < line.length && line[i] !== delimiter) {
          error = `Unexpected character '${line[i]}' after closing quote at position ${i}`;
          // Skip until next delimiter to recover
          while (i < line.length && line[i] !== delimiter) {
            current += line[i];
            i++;
          }
        }
        continue;
      }
      // Regular character inside quotes
      current += ch;
      i++;
    } else {
      if (ch === quote) {
        if (current.length === 0) {
          // Opening quote of a quoted field
          inQuotes = true;
          i++;
        } else {
          // Quote in the middle of an unquoted field – treat literally but flag
          error = `Unexpected quote character at position ${i} in unquoted field`;
          current += ch;
          i++;
        }
      } else if (ch === delimiter) {
        fields.push(current);
        current = "";
        i++;
      } else {
        current += ch;
        i++;
      }
    }
  }

  // Unterminated quoted field
  if (inQuotes) {
    error = "Unterminated quoted field (missing closing quote)";
  }

  // Push the last field
  fields.push(current);

  return { fields, error };
}

/**
 * Build a CSVResult object from already-parsed data.  This is factored out so
 * that `filter()` can cheaply wrap a subset of rows without re-parsing.
 */
function buildResult(
  rows: Record<string, unknown>[],
  headers: string[],
  errors: CSVError[]
): CSVResult {
  return {
    rows,
    headers,
    errors,

    filter(predicate: (row: Record<string, unknown>) => boolean): CSVResult {
      return buildResult(rows.filter(predicate), headers, errors);
    },

    sum(column: string): number {
      let total = 0;
      for (const row of rows) {
        const v = row[column];
        if (typeof v === "number") {
          total += v;
        }
      }
      return total;
    },

    average(column: string): number {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const v = row[column];
        if (typeof v === "number") {
          total += v;
          count++;
        }
      }
      return count === 0 ? NaN : total / count;
    },

    count(): number {
      return rows.length;
    },

    groupBy(column: string): Map<string, Record<string, unknown>[]> {
      const map = new Map<string, Record<string, unknown>[]>();
      for (const row of rows) {
        const key = String(row[column] ?? "null");
        let group = map.get(key);
        if (!group) {
          group = [];
          map.set(key, group);
        }
        group.push(row);
      }
      return map;
    },
  };
}

// ============================================================================
// Public API
// ============================================================================

/**
 * Parse a CSV string into a structured result.
 *
 * The first row is always treated as the header row.  Subsequent rows are
 * converted into objects keyed by header names.
 *
 * @param input   The raw CSV string.
 * @param options Optional parser configuration.
 * @returns       A CSVResult with rows, headers, errors, and utility methods.
 */
export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  const opts = { ...DEFAULT_OPTIONS, ...options };

  // Handle empty / whitespace-only input
  if (!input || input.trim().length === 0) {
    return buildResult([], [], []);
  }

  const lines = splitLines(input, opts.lineSeparator);

  // ---- Parse header row -------------------------------------------------
  const { fields: headers, error: headerError } = parseLine(
    lines[0],
    opts.delimiter,
    opts.quote
  );
  const errors: CSVError[] = [];

  if (headerError) {
    // We still try to continue with whatever headers we got
    errors.push({ row: 0, message: `Header row: ${headerError}` });
  }

  const trimmedHeaders = headers.map((h) => h.trim());

  // ---- Parse data rows --------------------------------------------------
  const rows: Record<string, unknown>[] = [];

  for (let i = 1; i < lines.length; i++) {
    const line = lines[i];

    // Skip completely empty trailing lines (common in files with trailing newline)
    if (line === "" && i === lines.length - 1) {
      continue;
    }

    const { fields, error } = parseLine(line, opts.delimiter, opts.quote);

    if (error) {
      errors.push({ row: i, message: error });
    }

    // Field count mismatch is a soft error – we still build the row
    if (fields.length !== trimmedHeaders.length) {
      errors.push({
        row: i,
        message: `Expected ${trimmedHeaders.length} fields but found ${fields.length}`,
      });
    }

    const row: Record<string, unknown> = {};
    for (let j = 0; j < trimmedHeaders.length; j++) {
      const raw = j < fields.length ? fields[j] : "";
      row[trimmedHeaders[j]] = opts.typeCoercion ? coerceValue(raw) : raw;
    }

    rows.push(row);
  }

  return buildResult(rows, trimmedHeaders, errors);
}

// ============================================================================
// CSV Parser – Comprehensive Test Suite
// ============================================================================
// No test framework – plain assertions.  Throws on first failure.
// Run with: npx ts-node csv-parser.test.ts   (or tsx, bun, etc.)
// ============================================================================

import { parseCSV } from "./csv-parser";

// ---------------------------------------------------------------------------
// Tiny assertion helpers
// ---------------------------------------------------------------------------
let passCount = 0;
let currentSuite = "";

function assert(condition: boolean, message: string): void {
  if (!condition) {
    throw new Error(`FAIL [${currentSuite}]: ${message}`);
  }
  passCount++;
}

function assertEqual(actual: unknown, expected: unknown, label: string): void {
  const a = JSON.stringify(actual);
  const e = JSON.stringify(expected);
  assert(a === e, `${label} — expected ${e}, got ${a}`);
}

function assertClose(actual: number, expected: number, label: string, epsilon = 1e-9): void {
  assert(
    Math.abs(actual - expected) < epsilon,
    `${label} — expected ~${expected}, got ${actual}`
  );
}

function suite(name: string, fn: () => void): void {
  currentSuite = name;
  console.log(`  ▸ ${name}`);
  fn();
}

// ============================================================================
// 1. Basic Parsing
// ============================================================================
suite("Basic parsing – simple CSV", () => {
  const csv = "name,age,city\nAlice,30,New York\nBob,25,London";
  const result = parseCSV(csv);

  assertEqual(result.headers, ["name", "age", "city"], "headers");
  assertEqual(result.rows.length, 2, "row count");

  assertEqual(result.rows[0]["name"], "Alice", "row 0 name");
  assertEqual(result.rows[0]["age"], 30, "row 0 age (coerced to number)");
  assertEqual(result.rows[0]["city"], "New York", "row 0 city");

  assertEqual(result.rows[1]["name"], "Bob", "row 1 name");
  assertEqual(result.rows[1]["age"], 25, "row 1 age");
  assertEqual(result.rows[1]["city"], "London", "row 1 city");

  assertEqual(result.errors.length, 0, "no errors");
});

suite("Basic parsing – trailing newline is ignored", () => {
  const csv = "a,b\n1,2\n";
  const result = parseCSV(csv);
  assertEqual(result.rows.length, 1, "row count");
  assertEqual(result.errors.length, 0, "no errors");
});

// ============================================================================
// 2. Quoted Fields
// ============================================================================
suite("Quoted fields – commas inside quotes", () => {
  const csv = 'name,address\nAlice,"123 Main St, Apt 4"\nBob,"456 Oak Ave, Suite 100"';
  const result = parseCSV(csv);

  assertEqual(result.rows[0]["address"], "123 Main St, Apt 4", "address with comma");
  assertEqual(result.rows[1]["address"], "456 Oak Ave, Suite 100", "address with comma");
  assertEqual(result.errors.length, 0, "no errors");
});

suite("Quoted fields – entire field is quoted with no special chars", () => {
  const csv = 'a,b\n"hello","world"';
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["a"], "hello", "a");
  assertEqual(result.rows[0]["b"], "world", "b");
});

suite("Quoted fields – field contains delimiter only", () => {
  const csv = 'x\n","';
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["x"], ",", "field is a single comma");
});

// ============================================================================
// 3. Escaped Quotes
// ============================================================================
suite("Escaped quotes – double quotes inside quoted field", () => {
  const csv = 'text\n"She said ""hello"""\n"A ""B"" C"';
  const result = parseCSV(csv);

  assertEqual(result.rows[0]["text"], 'She said "hello"', "escaped quotes row 0");
  assertEqual(result.rows[1]["text"], 'A "B" C', "escaped quotes row 1");
  assertEqual(result.errors.length, 0, "no errors");
});

suite("Escaped quotes – empty quoted string", () => {
  const csv = 'a\n""';
  const result = parseCSV(csv);
  // "" with no content inside → empty string → coerced to null
  assertEqual(result.rows[0]["a"], null, "empty quoted string → null");
});

suite("Escaped quotes – quoted field that is just escaped quotes", () => {
  const csv = 'a\n""""';
  const result = parseCSV(csv);
  // """" → content is a single " character
  assertEqual(result.rows[0]["a"], '"', 'four quotes → single literal quote');
});

// ============================================================================
// 4. Custom Delimiters
// ============================================================================
suite("Custom delimiter – tab-separated", () => {
  const csv = "name\tage\nAlice\t30\nBob\t25";
  const result = parseCSV(csv, { delimiter: "\t" });

  assertEqual(result.headers, ["name", "age"], "headers");
  assertEqual(result.rows[0]["name"], "Alice", "name");
  assertEqual(result.rows[0]["age"], 30, "age");
  assertEqual(result.rows.length, 2, "row count");
});

suite("Custom delimiter – semicolon", () => {
  const csv = "a;b;c\n1;2;3";
  const result = parseCSV(csv, { delimiter: ";" });

  assertEqual(result.headers, ["a", "b", "c"], "headers");
  assertEqual(result.rows[0]["a"], 1, "a");
  assertEqual(result.rows[0]["b"], 2, "b");
  assertEqual(result.rows[0]["c"], 3, "c");
});

suite("Custom delimiter – pipe", () => {
  const csv = "x|y\nhello|world";
  const result = parseCSV(csv, { delimiter: "|" });

  assertEqual(result.rows[0]["x"], "hello", "x");
  assertEqual(result.rows[0]["y"], "world", "y");
});

suite("Custom quote character – single quote", () => {
  const csv = "a,b\n'hello, world',42";
  const result = parseCSV(csv, { quote: "'" });

  assertEqual(result.rows[0]["a"], "hello, world", "single-quoted field");
  assertEqual(result.rows[0]["b"], 42, "numeric field");
});

suite("Custom line separator – explicit \\r\\n", () => {
  const csv = "a,b\r\n1,2\r\n3,4";
  const result = parseCSV(csv, { lineSeparator: "\r\n" });

  assertEqual(result.rows.length, 2, "row count");
  assertEqual(result.rows[0]["a"], 1, "first row a");
  assertEqual(result.rows[1]["a"], 3, "second row a");
});

suite("Auto-detect line separator – mixed \\r\\n and \\n", () => {
  const csv = "a,b\r\n1,2\n3,4";
  const result = parseCSV(csv);

