});

suite("Auto-detect line separator – bare \\r", () => {
  const csv = "a,b\r1,2\r3,4";
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 2, "row count");
  assertEqual(result.rows[0]["a"], 1, "first row a");
});

