suite("Type coercion – integers", () => {
  const csv = "v\n0\n42\n-7\n1000000";
  const result = parseCSV(csv);

  assertEqual(result.rows[0]["v"], 0, "zero");
  assertEqual(result.rows[1]["v"], 42, "positive int");
  assertEqual(result.rows[2]["v"], -7, "negative int");
  assertEqual(result.rows[3]["v"], 1000000, "large int");
});

suite("Type coercion – floats", () => {
  const csv = "v\n3.14\n-0.5\n.25\n100.0";
  const result = parseCSV(csv);

  assertClose(result.rows[0]["v"] as number, 3.14, "pi-ish");
  assertClose(result.rows[1]["v"] as number, -0.5, "negative float");
  assertClose(result.rows[2]["v"] as number, 0.25, "leading dot");
  assertClose(result.rows[3]["v"] as number, 100.0, "trailing .0");
});

suite("Type coercion – booleans", () => {
  const csv = "v\ntrue\nfalse\nTRUE\nFALSE\nTrue\nFalse";
  const result = parseCSV(csv);

  assertEqual(result.rows[0]["v"], true, "true");
  assertEqual(result.rows[1]["v"], false, "false");
  assertEqual(result.rows[2]["v"], true, "TRUE");
  assertEqual(result.rows[3]["v"], false, "FALSE");
  assertEqual(result.rows[4]["v"], true, "True");
  assertEqual(result.rows[5]["v"], false, "False");
});

suite("Type coercion – null values", () => {
  const csv = "v\nnull\nNULL\nNull\n";
  // The last line is empty string → should become null
  // BUT: trailing empty line is skipped as a trailing newline, so let's be explicit:
  const csv2 = "a,b\nnull,NULL\nNull,\nx,y";
  const result = parseCSV(csv2);

  assertEqual(result.rows[0]["a"], null, "null");
  assertEqual(result.rows[0]["b"], null, "NULL");
  assertEqual(result.rows[1]["a"], null, "Null");
  assertEqual(result.rows[1]["b"], null, "empty string → null");
  assertEqual(result.rows[2]["a"], "x", "normal string stays");
});

suite("Type coercion – strings that look numeric but aren't", () => {
  const csv = "v\n12abc\nabc\n1.2.3\n--5\nInfinity\nNaN";
  const result = parseCSV(csv);

  assertEqual(typeof result.rows[0]["v"], "string", "12abc is string");
  assertEqual(typeof result.rows[1]["v"], "string", "abc is string");
  assertEqual(typeof result.rows[2]["v"], "string", "1.2.3 is string");
  assertEqual(typeof result.rows[3]["v"], "string", "--5 is string");
  assertEqual(typeof result.rows[4]["v"], "string", "Infinity is string");
  assertEqual(typeof result.rows[5]["v"], "string", "NaN is string");
});

suite("Type coercion – disabled", () => {
  const csv = "a,b\n42,true\nnull,3.14";
  const result = parseCSV(csv, { typeCoercion: false });

  assertEqual(result.rows[0]["a"], "42", "42 stays string");
  assertEqual(result.rows[0]["b"], "true", "true stays string");
  assertEqual(result.rows[1]["a"], "null", "null stays string");
  assertEqual(result.rows[1]["b"], "3.14", "3.14 stays string");
});

// ============================================================================
// 6. Error Handling
// ============================================================================
suite("Malformed rows – too few fields", () => {
  const csv = "a,b,c\n1,2\n4,5,6";
  const result = parseCSV(csv);

  // Row with too few fields should still be included
  assertEqual(result.rows.length, 2, "both rows present");
  assertEqual(result.rows[0]["c"], null, "missing field → empty → null");

  // Error collected
  assert(result.errors.length >= 1, "at least one error");
  assert(
    result.errors.some((e) => e.row === 1 && e.message.includes("Expected 3")),
    "error mentions field count mismatch"
  );
});

suite("Malformed rows – too many fields", () => {
  const csv = "a,b\n1,2,3,4";
  const result = parseCSV(csv);

  assertEqual(result.rows.length, 1, "row present");
  assert(result.errors.length >= 1, "error collected");
  assert(
    result.errors.some((e) => e.message.includes("Expected 2") && e.message.includes("4")),
    "error describes mismatch"
  );
});

suite("Malformed rows – unterminated quote", () => {
  const csv = 'a,b\n"hello,world';
  const result = parseCSV(csv);

  // Parser should not crash
  assertEqual(result.rows.length, 1, "row present despite error");
  assert(result.errors.length >= 1, "error collected");
  assert(
    result.errors.some((e) => e.message.toLowerCase().includes("unterminated")),
