// ============================================================================
// CSV Parser – Comprehensive Test Suite
// ============================================================================
// No test framework – plain assertions.  Throws on first failure.
// Run with: npx ts-node csv-parser.test.ts   (or tsx, bun, etc.)
// ============================================================================

import { parseCSV } from "./csv-parser";

// ---------------------------------------------------------------------------
// Tiny assertion helpers
// ---------------------------------------------------------------------------
let passCount = 0;
let currentSuite = "";

function assert(condition: boolean, message: string): void {
  if (!condition) {
    throw new Error(`FAIL [${currentSuite}]: ${message}`);
  }
  passCount++;
}

function assertEqual(actual: unknown, expected: unknown, label: string): void {
  const a = JSON.stringify(actual);
  const e = JSON.stringify(expected);
  assert(a === e, `${label} — expected ${e}, got ${a}`);
}

function assertClose(actual: number, expected: number, label: string, epsilon = 1e-9): void {
  assert(
    Math.abs(actual - expected) < epsilon,
    `${label} — expected ~${expected}, got ${actual}`
  );
}

function suite(name: string, fn: () => void): void {
  currentSuite = name;
  console.log(`  ▸ ${name}`);
  fn();
}

